commit f2b5363268e1c2e72376877ec079cac40e86cb8b
Author: Kai Ingo Esser <iesser@users.noreply.github.com>
Date:   Mon Feb 2 12:55:39 2026 +0100

    Fix OpenXR API version to 1.0

    Sample is requesting 'XR_CURRENT_API_VERSION' which current resolves to 1.1, requiring a needlessly high OpenXR API version. Current SteamVR fails to initialize, for example.

    Setting this to 'XR_API_VERSION_1_0' fixes the issue and makes the sample compatible with future OpenXR SDK versions and runtimes.
---
 src/openxr_hmd.cu | 2 +-
 1 file changed, 1 insertion(+), 1 deletion(-)

diff --git a/src/openxr_hmd.cu b/src/openxr_hmd.cu
index a348e31..0aa7697 100644
--- a/src/openxr_hmd.cu
+++ b/src/openxr_hmd.cu
@@ -300,7 +300,7 @@ void OpenXRHMD::init_create_xr_instance() {
 	instance_create_info.applicationInfo.applicationVersion = 1;
 	strncpy(instance_create_info.applicationInfo.engineName, "Instant Neural Graphics Primitives v" NGP_VERSION, XR_MAX_ENGINE_NAME_SIZE);
 	instance_create_info.applicationInfo.engineVersion = 1;
-	instance_create_info.applicationInfo.apiVersion = XR_CURRENT_API_VERSION;
+	instance_create_info.applicationInfo.apiVersion = XR_API_VERSION_1_0;
 	instance_create_info.enabledExtensionCount = (uint32_t)extensions.size();
 	instance_create_info.enabledExtensionNames = extensions.data();
 	instance_create_info.enabledApiLayerCount = (uint32_t)layers.size();

