+				float theta = i*PI()*2.f/n;
+				ImColor col(sinf(theta)*0.4f+0.5f,sinf(theta+PI()*2.f/3.f)*0.4f+0.5f,sinf(theta+PI()*4.f/3.f)*0.4f+0.5f);
