+void add_debug_line(ImDrawList* list, const Matrix<float, 4, 4>& proj, Vector3f a, Vector3f b, uint32_t col, float thickness) {
+	ImVec2 aa, bb;
+	if (DebugProject(proj, a, aa) && DebugProject(proj, b, bb)) {
+		list->AddLine(aa, bb, col, thickness);
+	}
+}
