+			}
+			float child_size = std::scalbnf(1.f, -(int)n.depth - 1);
+			Vector3i16 child_pos_base = n.pos * (uint16_t)2;
+			for (int i = 0; i < 8; ++i) {
+				int child_idx = n.children[i];
